import java.util.*;
public class LRUCacheDemo {
    static class LRUCache {
        class Node{int key,val;Node prev,next;Node(int k,int v){key=k;val=v;}}
        Map<Integer,Node> map=new HashMap<>();Node head=new Node(0,0),tail=new Node(0,0);int cap;
        LRUCache(int c){cap=c;head.next=tail;tail.prev=head;}
        void remove(Node n){n.prev.next=n.next;n.next.prev=n.prev;}
        void addFront(Node n){n.next=head.next;n.prev=head;head.next.prev=n;head.next=n;}
        int get(int k){if(!map.containsKey(k))return -1;Node n=map.get(k);remove(n);addFront(n);return n.val;}
        void put(int k,int v){if(map.containsKey(k)){Node n=map.get(k);n.val=v;remove(n);addFront(n);return;}if(map.size()==cap){map.remove(tail.prev.key);remove(tail.prev);}Node n=new Node(k,v);addFront(n);map.put(k,n);}
    }
    public static void main(String[] a){
        LRUCache c=new LRUCache(2);c.put(1,1);c.put(2,2);
        System.out.println(c.get(1));  // 1
        c.put(3,3);                    // evicts 2
        System.out.println(c.get(2)); // -1
        System.out.println(c.get(3)); // 3
        System.out.println("O(1) get+put — HashMap + doubly linked list");
    }
}

import java.util.*;
public class TaskSched {
    public static int leastInterval(char[] tasks, int n) {
        int[] cnt=new int[26]; for(char t:tasks) cnt[t-'A']++;
        int maxCnt=0; for(int c:cnt) maxCnt=Math.max(maxCnt,c);
        int maxTasksWithMaxCnt=0; for(int c:cnt) if(c==maxCnt) maxTasksWithMaxCnt++;
        int slots=(maxCnt-1)*(n+1)+maxTasksWithMaxCnt;
        return Math.max(slots,tasks.length);
    }
    public static void main(String[] a){
        System.out.println(leastInterval(new char[]{'A','A','A','B','B','B'},2)); // 8
        System.out.println(leastInterval(new char[]{'A','A','A','B','B','B'},0)); // 6
        System.out.println("O(n) — max count formula, no queue needed");
    }
}

import java.util.*;
public class TwitterSimple {
    Map<Integer,List<int[]>> tweets=new HashMap<>();Map<Integer,Set<Integer>> follows=new HashMap<>();int ts=0;
    void postTweet(int userId,int tweetId){tweets.computeIfAbsent(userId,k->new ArrayList<>()).add(new int[]{ts++,tweetId});}
    void follow(int f,int ee){follows.computeIfAbsent(f,k->new HashSet<>()).add(ee);}
    void unfollow(int f,int ee){if(follows.containsKey(f))follows.get(f).remove(ee);}
    List<Integer> getNewsFeed(int userId){PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->b[0]-a[0]);List<int[]> own=tweets.getOrDefault(userId,new ArrayList<>());for(int i=Math.max(0,own.size()-10);i<own.size();i++)pq.offer(own.get(i));if(follows.containsKey(userId))for(int f:follows.get(userId)){List<int[]> ft=tweets.getOrDefault(f,new ArrayList<>());for(int i=Math.max(0,ft.size()-10);i<ft.size();i++)pq.offer(ft.get(i));}List<Integer> res=new ArrayList<>();while(!pq.isEmpty()&&res.size()<10)res.add(pq.poll()[1]);return res;}
    public static void main(String[] a){TwitterSimple t=new TwitterSimple();t.postTweet(1,5);t.postTweet(1,3);System.out.println(t.getNewsFeed(1));t.follow(2,1);System.out.println(t.getNewsFeed(2));System.out.println("Min-heap for top-10 feed merging");}
}

import java.util.*;
public class Calc1 {
    public static int calculate(String s) {
        Deque<Integer> stack=new ArrayDeque<>();int result=0,sign=1,num=0;
        for(char c:s.toCharArray()){
            if(Character.isDigit(c)) num=num*10+(c-'0');
            else if(c=='+'||c=='-'){result+=sign*num;num=0;sign=(c=='+'?1:-1);}
            else if(c=='('){stack.push(result);stack.push(sign);result=0;sign=1;}
            else if(c==')'){result+=sign*num;num=0;result*=stack.pop();result+=stack.pop();}
        }
        return result+sign*num;
    }
    public static void main(String[] a){
        System.out.println(calculate("1 + 1"));         // 2
        System.out.println(calculate(" 2-1 + 2 "));     // 3
        System.out.println(calculate("(1+(4+5+2)-3)+(6+8)")); // 23
        System.out.println("O(n) — stack saves result+sign on '(', restores on ')'");
    }
}

import java.util.*;
public class DecodeWays {
    public static int numDecodings(String s) {
        if(s.isEmpty()||s.charAt(0)=='0') return 0;
        int n=s.length(); int[] dp=new int[n+1]; dp[0]=1; dp[1]=1;
        for(int i=2;i<=n;i++){
            int oneDigit=Integer.parseInt(s.substring(i-1,i));
            int twoDigit=Integer.parseInt(s.substring(i-2,i));
            if(oneDigit>=1) dp[i]+=dp[i-1];
            if(twoDigit>=10&&twoDigit<=26) dp[i]+=dp[i-2];
        }
        return dp[n];
    }
    public static void main(String[] a){
        System.out.println(numDecodings("12")); // 2
        System.out.println(numDecodings("226")); // 3
        System.out.println(numDecodings("06"));  // 0
        System.out.println("O(n) DP — not strictly stack but uses similar state tracking");
    }
}

import java.util.*;
public class LFUSimple {
    // Simplified: track frequency + recency via LinkedHashMap
    int cap,minFreq=0;
    Map<Integer,Integer> keyVal=new HashMap<>(),keyFreq=new HashMap<>();
    Map<Integer,LinkedHashSet<Integer>> freqKeys=new HashMap<>();
    LFUSimple(int capacity){cap=capacity;}
    void updateFreq(int key){int f=keyFreq.get(key);keyFreq.put(key,f+1);freqKeys.computeIfAbsent(f,k->new LinkedHashSet<>()).remove(key);if(freqKeys.get(f).isEmpty()&&f==minFreq)minFreq++;freqKeys.computeIfAbsent(f+1,k->new LinkedHashSet<>()).add(key);}
    int get(int key){if(!keyVal.containsKey(key))return -1;updateFreq(key);return keyVal.get(key);}
    void put(int key,int val){if(cap==0)return;if(keyVal.containsKey(key)){keyVal.put(key,val);updateFreq(key);return;}if(keyVal.size()==cap){int evict=freqKeys.get(minFreq).iterator().next();freqKeys.get(minFreq).remove(evict);keyVal.remove(evict);keyFreq.remove(evict);}keyVal.put(key,val);keyFreq.put(key,1);freqKeys.computeIfAbsent(1,k->new LinkedHashSet<>()).add(key);minFreq=1;}
    public static void main(String[] a){LFUSimple lfu=new LFUSimple(2);lfu.put(1,1);lfu.put(2,2);System.out.println(lfu.get(1));lfu.put(3,3);System.out.println(lfu.get(2));System.out.println(lfu.get(3));System.out.println("O(1) LFU: freq map + LinkedHashSet for ordering within freq");}
}

import java.util.*;
public class StockFluctuation {
    Map<Integer,Integer> prices=new HashMap<>();TreeMap<Integer,Integer> priceCount=new TreeMap<>();
    void update(int timestamp, int price){
        if(prices.containsKey(timestamp)){int old=prices.get(timestamp);priceCount.merge(old,-1,Integer::sum);if(priceCount.get(old)==0)priceCount.remove(old);}
        prices.put(timestamp,price);priceCount.merge(price,1,Integer::sum);
    }
    int current(){return prices.get(prices.keySet().stream().mapToInt(x->x).max().getAsInt());}
    int maximum(){return priceCount.lastKey();}
    int minimum(){return priceCount.firstKey();}
    public static void main(String[] a){StockFluctuation sf=new StockFluctuation();sf.update(1,10);sf.update(2,5);sf.update(1,3);sf.update(4,2);System.out.println(sf.current());System.out.println(sf.maximum());System.out.println(sf.minimum());System.out.println("O(log n) update/max/min using TreeMap");}
}

import java.util.*;
public class BrowserHist {
    Deque<String> back=new ArrayDeque<>(),forward=new ArrayDeque<>();String curr;
    BrowserHist(String homepage){curr=homepage;}
    void visit(String url){back.push(curr);curr=url;forward.clear();}
    String back(int steps){while(steps-->0&&!back.isEmpty()){forward.push(curr);curr=back.pop();}return curr;}
    String forward(int steps){while(steps-->0&&!forward.isEmpty()){back.push(curr);curr=forward.pop();}return curr;}
    public static void main(String[] a){BrowserHist bh=new BrowserHist("leetcode.com");bh.visit("google.com");bh.visit("facebook.com");bh.visit("youtube.com");System.out.println(bh.back(1));System.out.println(bh.back(1));System.out.println(bh.forward(1));System.out.println("Two stacks = browser back/forward history");}
}

import java.util.*;
public class MinStackFull {
    Deque<Long> stack=new ArrayDeque<>();long min;
    void push(long v){if(stack.isEmpty()){stack.push(0L);min=v;}else{stack.push(v-min);if(v<min)min=v;}}
    void pop(){long top=stack.pop();if(top<0)min=min-top;}
    long top(){long top=stack.peek();return top>0?top+min:min;}
    long getMin(){return min;}
    public static void main(String[] a){MinStackFull ms=new MinStackFull();ms.push(5);ms.push(3);ms.push(7);ms.push(2);System.out.println(ms.getMin());ms.pop();System.out.println(ms.getMin());ms.pop();System.out.println(ms.getMin());System.out.println("O(1) space trick: store (val-min) as delta to track min without aux stack");}
}

import java.util.*;
public class SQSynth {
    // LRU simplified
    static int lruTest(){LinkedHashMap<Integer,Integer> cache=new LinkedHashMap<>(2,0.75f,true){protected boolean removeEldestEntry(Map.Entry<Integer,Integer> e){return size()>2;}};cache.put(1,1);cache.put(2,2);cache.get(1);cache.put(3,3);return cache.getOrDefault(2,-1);}
    static int calcII(String s){Deque<Integer> st=new ArrayDeque<>();int num=0;char op='+';for(int i=0;i<s.length();i++){char c=s.charAt(i);if(Character.isDigit(c))num=num*10+(c-'0');if((!Character.isDigit(c)&&c!=' ')||i==s.length()-1){if(op=='+')st.push(num);else if(op=='-')st.push(-num);else if(op=='*')st.push(st.pop()*num);else st.push(st.pop()/num);op=c;num=0;}}int r=0;while(!st.isEmpty())r+=st.pop();return r;}
    static int sched(char[] t,int n){int[] c=new int[26];for(char x:t)c[x-'A']++;int max=0;for(int x:c)max=Math.max(max,x);int cnt=0;for(int x:c)if(x==max)cnt++;return Math.max((max-1)*(n+1)+cnt,t.length);}
    public static void main(String[] a){System.out.println("lru="+lruTest());System.out.println("calc="+calcII("3+2*2"));System.out.println("sched="+sched(new char[]{'A','A','A','B','B','B'},2));boolean ok=lruTest()==-1&&calcII("3+2*2")==7&&sched(new char[]{'A','A','A','B','B','B'},2)==8;System.out.println("All pass: "+ok);}
}

